trigger.body:
 v_value VARCHAR2(60);

BEGIN

 IF AD_isTriggerEnabled()='N' THEN RETURN;
  END IF;


  IF (INSERTING OR UPDATING OR DELETING ) THEN

    SELECT COALESCE(( 	SELECT value
                        FROM ad_preference
                        WHERE property = 'Sccc_CloseCashDoctype'
                        AND created = ( SELECT MAX(created) FROM ad_preference 
                        WHERE property = 'Sccc_CloseCashDoctype')
                ),'N')
    INTO v_value
    FROM DUAL;  

	IF (v_value = 'Y' AND (:new.c_doctype_sales_id IS NULL OR :new.c_doctype_credit_notes_id IS NULL OR :new.c_doctype_reversed_id IS NULL)) THEN
		RAISE_APPLICATION_ERROR(-20000, '@Sccc_DoctypeNotNull@');
	END IF;

  END IF;


  END SCCC_DOCTYPE_NOT_NULL_TRG
